export default function recoverBST(root) {
  if (!root) return root;

  let first = null;
  let second = null;
  let prev = null;

  const dfs = (node) => {
    if (!node) return;
    dfs(node.left);

    if (prev && prev.val > node.val) {
      if (!first) first = prev;
      second = node;
    }
    prev = node;

    dfs(node.right);
  };

  dfs(root);

  if (first && second) {
    const tmp = first.val;
    first.val = second.val;
    second.val = tmp;
  }

  return root;
}
